            <b>{email}</b> <span style={{ color: '#1677ff', marginLeft: 8 }}>[secondary]</span>
          </div>
          <Button type="primary" danger onClick={logout}>Logout</Button>
        </Header>
        <Content style={{ margin: 24, background: '#fff', borderRadius: 8, minHeight: 400, padding: 24 }}>
