        setSuccessMsg('Finishing time updated successfully!');
        setTimeout(() => setSuccessMsg(''), 2000);
        // Refresh user details
        const userRes = await fetch(`${API_URL}/api/users/${selectedId}`, {
          headers: { 'Authorization': `Bearer ${token}` },
